import { Component, OnInit, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule, Router } from '@angular/router';
import { DocenteDashboardService, DocenteCurso } from '../../../../core/services/docente-dashboard.service';
import { FormsModule } from '@angular/forms';
import { matchesQuery, paginate, sortByDate, totalPages, SortOrder } from '../../../../core/utils/listing.utils';

@Component({
  selector: 'app-mis-cursos-docente',
  standalone: true,
  imports: [CommonModule, RouterModule, FormsModule],
  templateUrl: './mis-cursos-docente.component.html',
  styleUrls: ['./mis-cursos-docente.component.css']
})
export class MisCursosDocenteComponent implements OnInit {
  private docenteService = inject(DocenteDashboardService);
  private router = inject(Router);

  cursos: DocenteCurso[] = [];
  isLoading = true;
  searchTerm = '';
  dateSortOrder: SortOrder = 'desc';
  currentPage = 1;
  pageSize = 6;

  ngOnInit(): void {
    this.docenteService.getCursosAsignados().subscribe({
      next: (data) => {
        this.cursos = data;
        this.isLoading = false;
      },
      error: (err) => {
        console.error('Error fetching assigned courses:', err);
        this.isLoading = false;
      }
    });
  }

  get filteredCursos(): DocenteCurso[] {
    const matches = this.cursos.filter(curso =>
      matchesQuery([
        curso.nombre,
        curso.descripcion,
        curso.docenteNombre,
        curso.fechaCreacion
      ], this.searchTerm)
    );
    return sortByDate(matches, curso => curso.fechaCreacion, this.dateSortOrder);
  }

  get totalPages(): number {
    return totalPages(this.filteredCursos.length, this.pageSize);
  }

  get pagedCursos(): DocenteCurso[] {
    return paginate(this.filteredCursos, this.currentPage, this.pageSize);
  }

  onSearchChange(): void {
    this.currentPage = 1;
  }

  toggleDateSort(): void {
    this.dateSortOrder = this.dateSortOrder === 'desc' ? 'asc' : 'desc';
    this.currentPage = 1;
  }

  previousPage(): void {
    if (this.currentPage > 1) this.currentPage--;
  }

  nextPage(): void {
    if (this.currentPage < this.totalPages) this.currentPage++;
  }

  manageContent(courseId: number): void {
    this.router.navigate(['/dashboard/cursos', courseId]);
  }

  viewStudents(courseId: number): void {
    this.router.navigate(['/dashboard/mis-alumnos-docente', courseId]);
  }
}
<div class="space-y-8 font-body">

  <!-- Banner Header -->
  <div class="border border-slate-200 dark:border-slate-800 p-8 bg-white dark:bg-slate-900 rounded-none shadow-sm transition-colors duration-300">
    <h1 class="text-2xl font-black text-slate-900 dark:text-white tracking-tight uppercase leading-none">Mis Cursos (Docente)</h1>
    <p class="text-slate-500 dark:text-slate-400 text-xs mt-2">Administra y edita la estructura curricular de tus cursos asignados. Monitorea el progreso de tus alumnos en tiempo real.</p>
  </div>

  <!-- Loading State -->
  <div *ngIf="isLoading" class="flex flex-col items-center justify-center p-20 border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 transition-colors duration-300">
    <span class="animate-spin inline-block w-8 h-8 border-4 border-primary border-t-transparent rounded-full mb-3"></span>
    <span class="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-widest">Cargando tus cursos asignados...</span>
  </div>

  <!-- No courses state -->
  <div *ngIf="!isLoading && cursos.length === 0" class="border border-slate-200 dark:border-slate-800 p-12 text-center bg-white dark:bg-slate-900 transition-colors duration-300">
    <span class="material-symbols-outlined text-5xl text-slate-300 dark:text-slate-600 mb-2">auto_stories</span>
    <h3 class="text-sm font-bold text-slate-800 dark:text-slate-200 uppercase">Sin Cursos Asignados</h3>
    <p class="text-slate-500 dark:text-slate-400 text-xs mt-1.5 max-w-sm mx-auto">No tienes cursos asignados actualmente. Solicita al administrador del sistema que te asigne la propiedad de algún programa educativo.</p>
  </div>

  <!-- Courses Grid -->
  <div *ngIf="!isLoading && cursos.length > 0" class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
    <div 
      *ngFor="let curso of cursos"
      class="border border-slate-200 dark:border-slate-800 bg-white dark:bg-slate-900 flex flex-col justify-between rounded-none hover:shadow-lg transition-all overflow-hidden duration-300">

      <!-- Top header portadas -->
      <div>
        <div class="relative h-44 bg-slate-100 dark:bg-slate-950 border-b border-slate-200 dark:border-slate-800 overflow-hidden">
          <img 
            [src]="curso.imagenPortada || 'https://images.unsplash.com/photo-1516321318423-f06f85e504b3'" 
            class="w-full h-full object-cover transition-transform duration-500 hover:scale-105" 
            alt="Portada Curso">

          <div class="absolute top-3 right-3 flex flex-wrap gap-1">
            <span 
              *ngFor="let nivel of curso.nivelesSuscripcion"
              [ngClass]="{
                'bg-emerald-50 dark:bg-emerald-950/45 text-emerald-700 dark:text-emerald-300 border-emerald-200 dark:border-emerald-900': nivel === 'BASICO',
                'bg-blue-50 dark:bg-blue-950/45 text-blue-700 dark:text-blue-300 border-blue-200 dark:border-indigo-900': nivel === 'INTERMEDIO',
                'bg-amber-50 dark:bg-amber-950/45 text-amber-700 dark:text-amber-300 border-amber-200 dark:border-amber-900': nivel === 'PREMIUM'
              }" 
              class="text-[9px] font-black uppercase tracking-widest border px-2 py-0.5 rounded-none shadow-[2px_2px_0px_0px_rgba(15,23,42,0.1)]">
              {{ nivel }}
            </span>
          </div>
        </div>

        <!-- Body context -->
        <div class="p-6">
          <div class="flex items-center gap-1.5 text-[9px] font-bold text-slate-400 dark:text-slate-500 uppercase tracking-widest mb-1.5">
            <span class="material-symbols-outlined text-xs">calendar_today</span>
            <span>Curso Activo</span>
          </div>
          <h2 class="text-sm font-black text-slate-900 dark:text-white uppercase tracking-tight leading-snug line-clamp-1">
            {{ curso.nombre }}
          </h2>
          <p class="text-slate-500 dark:text-slate-400 text-xs mt-2 line-clamp-3 leading-relaxed">
            {{ curso.descripcion }}
          </p>
        </div>
      </div>

      <!-- Footer Actions -->
      <div class="p-6 pt-0 border-t border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/50 flex flex-col gap-2">
        <div class="grid grid-cols-2 gap-3 mt-4">
          <button 
            (click)="manageContent(curso.id)" 
            class="py-2 px-3 bg-slate-900 dark:bg-slate-800 text-white font-bold text-[10px] uppercase tracking-wider hover:bg-slate-800 dark:hover:bg-slate-700 transition-colors rounded-none border border-slate-900 dark:border-slate-800 flex items-center justify-center gap-1.5">
            <span class="material-symbols-outlined text-xs">edit</span>
            <span>Temario</span>
          </button>

          <button 
            (click)="viewStudents(curso.id)" 
            class="py-2 px-3 bg-white dark:bg-slate-800 text-slate-700 dark:text-slate-300 font-bold text-[10px] uppercase tracking-wider hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors rounded-none border border-slate-200 dark:border-slate-700 flex items-center justify-center gap-1.5">
            <span class="material-symbols-outlined text-xs">group</span>
            <span>Estudiantes</span>
          </button>
        </div>
      </div>

    </div>
  </div>

</div>
